external_knowledge:
; Top-ranked reports refer to the reports with the highest total amounts within each report type; 
; The reports are categorized into three tiers based on their total amounts, with the top tier having the highest total amounts;
; The reports are ordered in descending order of total amount within each report type.

sql:
SELECT compensation, expenses, total_amount
FROM financial_reports
WHERE report_id = 0;

SELECT audit_notes
FROM audit_reports
WHERE audit_id = 1;
